// src/wordsbysize.ts
// Word lists keyed by word length (4..12).
// Length 5 keeps separate answer + valid-guess pools (classic Wordle).
// All other lengths use a single pool that doubles as answers and valid guesses.
// Data is comma-joined uppercase strings; reconstructed verbatim from the
// deployed worker bundle (the source of truth for this generated module).

export interface WordPool {
  /** Candidate answers for this length (a random one is chosen per round). */
  answers: string[];
  /** Full set of accepted guesses for this length. */
  valid: Set<string>;
}

function unpack(raw: string): WordPool {
  const arr = raw.split(",");
  return { answers: arr, valid: new Set(arr) };
}

function unpackPair(answersRaw: string, validRaw: string): WordPool {
  return { answers: answersRaw.split(","), valid: new Set(validRaw.split(",")) };
}

