export const WORDS_BY_SIZE: Record<number, WordPool> = {
  4: unpack(W4),
  5: unpackPair(A5, V5),
  6: unpack(W6),
  7: unpack(W7),
  8: unpack(W8),
  9: unpack(W9),
  10: unpack(W10),
  11: unpack(W11),
  12: unpack(W12),
};

export function isSupportedSize(n: number): boolean {
  return Number.isInteger(n) && n >= 4 && n <= 12;
}
